CREATE OR REPLACE FUNCTION fpa_lon_bal_by_loantype (as_memno char,as_loantype char) RETURNS bigint AS $body$
DECLARE

  ldc_balance bigint;

BEGIN
  select sum(sc_lon_m_loan_card.principal_balance) into STRICT ldc_balance
  from sc_mem_m_membership_registered,
      sc_lon_m_loan_card,
      sc_lon_m_rule
  where (sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no)
  and (sc_lon_m_rule.loan_type = sc_lon_m_loan_card.loan_type)
  and (sc_mem_m_membership_registered.membership_no = as_memno)
  and (sc_lon_m_rule.loan_type = as_loantype)
  and (sc_lon_m_loan_card.principal_balance > 0)
;

  return coalesce(ldc_balance,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
